@using sv_8216807009b2413ab097b7191bc22227.Services

<div class="channel-item @(IsActive ? "active" : "")" @onclick="OnClick">
    <div class="channel-header">
        <span class="channel-name"># @Channel.Name</span>
        @if (Channel.UnreadCount > 0)
        {
            <span class="unread-badge">@Channel.UnreadCount</span>
        }
    </div>
    <div class="channel-description">@Channel.Description</div>
</div>

@code {
    [Parameter, EditorRequired] public Channel Channel { get; set; } = default!;
    [Parameter] public bool IsActive { get; set; }
    [Parameter] public EventCallback<Channel> OnSelected { get; set; }

    private async Task OnClick() => await OnSelected.InvokeAsync(Channel);
}

::deep .channel-item {
    padding: 8px 12px;
    cursor: pointer;
    border-radius: 6px;
    margin: 2px 8px;
    transition: background-color 0.15s;
}

::deep .channel-item:hover {
    background-color: rgba(255, 255, 255, 0.08);
}

::deep .channel-item.active {
    background-color: rgba(255, 255, 255, 0.15);
}

::deep .channel-header {
    display: flex;
    align-items: center;
    justify-content: space-between;
    gap: 8px;
}

::deep .channel-name {
    font-weight: 600;
    font-size: 0.95rem;
    color: #e0e0e0;
    overflow: hidden;
    text-overflow: ellipsis;
    white-space: nowrap;
}

::deep .channel-item.active .channel-name {
    color: #fff;
}

::deep .unread-badge {
    background-color: #e74c3c;
    color: #fff;
    font-size: 0.7rem;
    font-weight: 700;
    padding: 1px 6px;
    border-radius: 10px;
    min-width: 18px;
    text-align: center;
    flex-shrink: 0;
}

::deep .channel-description {
    font-size: 0.78rem;
    color: #999;
    overflow: hidden;
    text-overflow: ellipsis;
    white-space: nowrap;
    margin-top: 2px;
}

@using sv_8216807009b2413ab097b7191bc22227.Services

<div class="message-input-area">
    <textarea class="message-textarea"
              @bind="text"
              @bind:event="oninput"
              @onkeydown="HandleKeyDown"
              placeholder="@Placeholder"
              rows="2"></textarea>
    <button class="send-button" @onclick="HandleSend" disabled="@string.IsNullOrWhiteSpace(text)">
        @ButtonLabel
    </button>
</div>

@code {
    [Parameter] public string Placeholder { get; set; } = "Type a message…";
    [Parameter] public string ButtonLabel { get; set; } = "Send";
    [Parameter] public EventCallback<string> OnSend { get; set; }

    private string text = "";

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (e is { Key: "Enter", ShiftKey: false })
        {
            await HandleSend();
        }
    }

    private async Task HandleSend()
    {
        var content = text.Trim();
        if (string.IsNullOrEmpty(content)) return;
        text = "";
        await OnSend.InvokeAsync(content);
    }
}

::deep .message-input-area {
    display: flex;
    gap: 8px;
    padding: 12px 16px;
    border-top: 1px solid #e0e0e0;
    background: #fff;
    align-items: flex-end;
}

::deep .message-textarea {
    flex: 1;
    resize: none;
    border: 1px solid #ccc;
    border-radius: 8px;
    padding: 8px 12px;
    font-size: 0.9rem;
    font-family: inherit;
    outline: none;
    transition: border-color 0.15s;
}

::deep .message-textarea:focus {
    border-color: #4a76a8;
}

::deep .send-button {
    padding: 8px 20px;
    background-color: #4a76a8;
    color: #fff;
    border: none;
    border-radius: 8px;
    font-weight: 600;
    cursor: pointer;
    transition: background-color 0.15s;
    white-space: nowrap;
}

::deep .send-button:hover:not(:disabled) {
    background-color: #3a6090;
}

::deep .send-button:disabled {
    opacity: 0.5;
    cursor: not-allowed;
}

