arguments.file_text:
@using sv_8216807009b2413ab097b7191bc22227.Services

<div class="thread-panel">
    <div class="thread-header">
        <h4>Thread</h4>
        <button class="close-button" @onclick="OnClose" title="Close thread">✕</button>
    </div>
    @if (RootMessage is not null)
    {
        <div class="thread-root-message">
            <span class="root-author">@RootMessage.Author</span>
            <p class="root-content">@RootMessage.Content</p>
        </div>
        <div class="thread-replies">
            @foreach (var reply in Replies)
            {
                <div class="thread-reply">
                    <div class="reply-header">
                        <span class="reply-author">@reply.Author</span>
                        <span class="reply-time">@FormatRelativeTime(reply.SentAt)</span>
                    </div>
                    <div class="reply-content">@reply.Content</div>
                </div>
            }
        </div>
        <MessageInput Placeholder="Reply in thread…"
                      ButtonLabel="Reply"
                      OnSend="OnSendReply" />
    }
</div>

@code {
    [Parameter] public Message? RootMessage { get; set; }
    [Parameter] public List<Message> Replies { get; set; } = [];
    [Parameter] public EventCallback OnClose { get; set; }
    [Parameter] public EventCallback<string> OnSendReply { get; set; }

    private static string FormatRelativeTime(DateTime sentAt)
    {
        var diff = DateTime.UtcNow - sentAt;
        if (diff.TotalMinutes < 1) return "just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes} min ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        if (diff.TotalDays < 7) return $"{(int)diff.TotalDays}d ago";
        return sentAt.ToString("MMM d, yyyy");
    }
}

::deep .thread-panel {
    display: flex;
    flex-direction: column;
    height: 100%;
    background: #fff;
    border-left: 1px solid #e0e0e0;
}

::deep .thread-header {
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 12px 16px;
    border-bottom: 1px solid #e0e0e0;
}

::deep .thread-header h4 {
    margin: 0;
    font-size: 1rem;
    font-weight: 700;
}

::deep .close-button {
    background: none;
    border: none;
    font-size: 1.1rem;
    cursor: pointer;
    color: #666;
    padding: 4px 8px;
    border-radius: 4px;
}

::deep .close-button:hover {
    background-color: #f0f0f0;
    color: #333;
}

::deep .thread-root-message {
    padding: 12px 16px;
    background: #f9f9f9;
    border-bottom: 1px solid #e0e0e0;
}

::deep .root-author {
    font-weight: 700;
    font-size: 0.9rem;
    color: #1a1a1a;
}

::deep .root-content {
    margin: 4px 0 0;
    font-size: 0.9rem;
    color: #444;
    white-space: pre-wrap;
    word-break: break-word;
}

::deep .thread-replies {
    flex: 1;
    overflow-y: auto;
    padding: 8px 0;
}

::deep .thread-reply {
    padding: 8px 16px;
}

::deep .reply-header {
    display: flex;
    align-items: baseline;
    gap: 8px;
    margin-bottom: 2px;
}

::deep .reply-author {
    font-weight: 700;
    font-size: 0.88rem;
    color: #1a1a1a;
}

::deep .reply-time {
    font-size: 0.73rem;
    color: #999;
}

::deep .reply-content {
    font-size: 0.9rem;
    color: #333;
    white-space: pre-wrap;
    word-break: break-word;
}

