<PageTitle>Chat</PageTitle>

<div class="chat-layout">
    <div class="sidebar-column">
        <ChannelSidebar Channels="channels"
                        ActiveChannelId="selectedChannelId"
                        OnChannelSelected="SelectChannel" />
    </div>

    <div class="main-column @(isThreadOpen ? "" : "main-expanded")">
        @if (activeChannel is not null)
        {
            <div class="channel-header-bar">
                <h2># @activeChannel.Name</h2>
                <span class="channel-desc">@activeChannel.Description</span>
            </div>
            <MessageList Messages="messages"
                         ThreadSummaries="threadSummaries"
                         HasMore="hasMoreMessages"
                         OnOpenThread="OpenThread"
                         OnReact="HandleReaction"
                         OnLoadMore="LoadOlderMessages" />
            <MessageInput Placeholder="@($"Message #{activeChannel.Name}")"
                          OnSend="SendMessage" />
        }
        else
        {
            <div class="empty-state">Select a channel to start chatting</div>
        }
    </div>

    @if (isThreadOpen)
    {
        <div class="thread-column">
            <ThreadPanel RootMessage="threadRootMessage"
                         Replies="threadReplies"
                         OnClose="CloseThread"
                         OnSendReply="SendThreadReply" />
        </div>
    }
</div>

@code {
    private List<Channel> channels = [];
    private List<Message> messages = [];
    private Dictionary<int, ThreadSummary> threadSummaries = [];
    private Channel? activeChannel;
    private int selectedChannelId;
    private bool hasMoreMessages = true;

    private bool isThreadOpen;
    private Message? threadRootMessage;
    private List<Message> threadReplies = [];
    private int activeThreadRootId;

    private const int PageSize = 30;

    protected override async Task OnInitializedAsync()
    {
        channels = await ChatService.GetChannelsAsync();
        if (channels.Count > 0)
        {
            await SelectChannel(channels[0]);
        }
    }

    private async Task SelectChannel(Channel channel)
    {
        activeChannel = channel;
        selectedChannelId = channel.Id;
        messages = [];
        hasMoreMessages = true;
        threadSummaries = [];

        CloseThreadInternal();

        var loaded = await ChatService.GetMessagesAsync(channel.Id, 0, PageSize);
        messages = loaded;
        hasMoreMessages = loaded.Count >= PageSize;

        await BuildThreadSummaries();
        await ChatService.MarkChannelReadAsync(channel.Id);

        // Refresh unread count in sidebar
        channels = await ChatService.GetChannelsAsync();
    }

    private async Task LoadOlderMessages()
    {
        if (activeChannel is null) return;

        var older = await ChatService.GetMessagesAsync(activeChannel.Id, messages.Count, PageSize);
        if (older.Count < PageSize) hasMoreMessages = false;

        messages.InsertRange(0, older);
        await BuildThreadSummaries();
    }

    private async Task SendMessage(string content)
    {
        if (activeChannel is null) return;

        var newMsg = await ChatService.SendMessageAsync(activeChannel.Id, content, null);
        messages.Add(newMsg);
    }

    private async Task HandleReaction((int MessageId, string Emoji) args)
    {
        await ChatService.AddReactionAsync(args.MessageId, args.Emoji);

        // Reload messages to reflect updated reactions
        if (activeChannel is not null)
        {
            messages = await ChatService.GetMessagesAsync(activeChannel.Id, 0, messages.Count);
        }
    }

    private async Task OpenThread(int rootMessageId)
    {
        activeThreadRootId = rootMessageId;
        threadRootMessage = messages.FirstOrDefault(m => m.Id == rootMessageId);

        var threadMessages = await ChatService.GetThreadAsync(rootMessageId);
        threadReplies = threadMessages.Where(m => m.Id != rootMessageId).ToList();

        isThreadOpen = true;
    }

    private async Task SendThreadReply(string content)
    {
        if (activeChannel is null) return;

        var reply = await ChatService.SendMessageAsync(activeChannel.Id, content, activeThreadRootId);
        threadReplies.Add(reply);

        await BuildThreadSummaries();
    }

    private void CloseThread()
    {
        CloseThreadInternal();
    }

    private void CloseThreadInternal()
    {
        isThreadOpen = false;
        threadRootMessage = null;
        threadReplies = [];
        activeThreadRootId = 0;
    }

    private async Task BuildThreadSummaries()
    {
        // Build thread summaries from messages that have replies
        var rootIds = messages
            .Where(m => m.ReplyToId is not null)
            .Select(m => m.ReplyToId!.Value)
            .Distinct();

        var summaries = new Dictionary<int, ThreadSummary>();
        foreach (var rootId in rootIds)
        {
            var replies = messages.Where(m => m.ReplyToId == rootId).ToList();
            if (replies.Count > 0)
            {
                summaries[rootId] = new ThreadSummary(rootId, replies.Count, replies.Max(r => r.SentAt));
            }
        }

        // Also check via GetThreadAsync for threads whose replies aren't in the current page
        foreach (var msg in messages.Where(m => m.ReplyToId is null && !summaries.ContainsKey(m.Id)))
        {
            try
            {
                var thread = await ChatService.GetThreadAsync(msg.Id);
                var replies = thread.Where(t => t.Id != msg.Id).ToList();
                if (replies.Count > 0)
                {
                    summaries[msg.Id] = new ThreadSummary(msg.Id, replies.Count, replies.Max(r => r.SentAt));
                }
            }
            catch
            {
                // Thread may not exist for this message
            }
        }

        threadSummaries = summaries;
    }
}

