::deep .chat-layout {
    display: flex;
    height: 100vh;
    overflow: hidden;
    font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif;
}

::deep .sidebar-column {
    width: 20%;
    min-width: 200px;
    max-width: 280px;
    flex-shrink: 0;
}

::deep .main-column {
    flex: 55;
    display: flex;
    flex-direction: column;
    min-width: 0;
    background: #fff;
}

::deep .main-column.main-expanded {
    flex: 80;
}

::deep .thread-column {
    flex: 25;
    min-width: 280px;
    max-width: 400px;
    flex-shrink: 0;
}

::deep .channel-header-bar {
    display: flex;
    align-items: baseline;
    gap: 12px;
    padding: 12px 16px;
    border-bottom: 1px solid #e0e0e0;
    background: #fff;
    flex-shrink: 0;
}

::deep .channel-header-bar h2 {
    margin: 0;
    font-size: 1.15rem;
    font-weight: 700;
    color: #1a1a1a;
    white-space: nowrap;
}

::deep .channel-desc {
    font-size: 0.85rem;
    color: #888;
    overflow: hidden;
    text-overflow: ellipsis;
    white-space: nowrap;
}

::deep .empty-state {
    display: flex;
    align-items: center;
    justify-content: center;
    flex: 1;
    color: #999;
    font-size: 1.1rem;
}

